// SRP vectors generated by pysrp (srp._pysrp with rfc5054_enable +
// no_username_in_x, SHA-256, NG_2048) — the exact configuration FindMy.py uses
// against Apple GSA. The ephemeral `a` was pinned so A/M1/K are deterministic.

import { test } from 'node:test';
import assert from 'node:assert/strict';
import { SrpClient, encryptPassword } from './srp';

const hex = (s: string) => new Uint8Array(Buffer.from(s, 'hex'));
const toHex = (b: Uint8Array) => Buffer.from(b).toString('hex');

const USERNAME = 'burner.test@icloud.com';
const PASSWORD = 'Sup3r-Secret-Pw!';
const SALT = hex('00112233445566778899aabbccddeeff');
const ITER = 1000;
const A_PRIV = hex('1a'.repeat(256));
const A_PUB =
  '';
const B =
  '';
const PK = 'a2af0f057e1d21bc1477e350b4b5829fcf45650692f0a4812a643b616b0eeca2';
const PK_S2KFO = '7f90ba9058f7e5c95ce835e5efb05b54380ad85441ecd0e898a40593afffd333';
const M1 = 'bfdf86ab7b21a2cebfa4bb13a14ef240be0c97e1a87a4d6e34bb3781f53b6451';
const K = '6dd25a5aca7e45612c9ab09b9e514498104be2e8ee75d078ed5dab591c2029b1';

test('encryptPassword matches pysrp for s2k and s2k_fo', () => {
  assert.equal(toHex(encryptPassword(PASSWORD, SALT, ITER, 's2k')), PK);
  assert.equal(toHex(encryptPassword(PASSWORD, SALT, ITER, 's2k_fo')), PK_S2KFO);
});

test('SRP A / M1 / K match pysrp', () => {
  const client = new SrpClient(USERNAME, A_PRIV);
  assert.equal(toHex(client.A), A_PUB);
  const { m1, sessionKey } = client.processChallenge(SALT, hex(B), hex(PK));
  assert.equal(toHex(m1), M1);
  assert.equal(toHex(sessionKey), K);
});
